from dataclasses import dataclass

@dataclass
class ContextWindow:
    chunks: list[Chunk]
    total_tokens: int
    citations: list[dict]

def assemble_context(
    chunks: list[Chunk],
    reranker,
    query: str,
    max_context_tokens: int = 6000,
    tokenizer=None,
) -> ContextWindow:
    # Re-rank
    scores = reranker.predict([(query, c.text) for c in chunks])
    ranked = sorted(zip(chunks, scores), key=lambda x: x[1], reverse=True)

    selected, total_tokens, citations = [], 0, []
    for chunk, score in ranked:
        tokens = len(tokenizer.encode(chunk.text)) if tokenizer else len(chunk.text) // 4
        if total_tokens + tokens > max_context_tokens:
            break
        selected.append(chunk)
        total_tokens += tokens
        citations.append({
            "doc_id": chunk.doc_id,
            "chunk_id": chunk.chunk_id,
            "relevance_score": round(score, 4),
            "source_title": chunk.metadata.get("title", ""),
        })

    return ContextWindow(chunks=selected, total_tokens=total_tokens, citations=citations)
